    keywords: ["administrative","Upravni sud Crne Gore","U"],
    related_articles: ["čl. 37. ZUS CG"],
    headnote: "Tužbase odbija. ObrazloženjeOsporenim rješenjem odbijenaje žalba tužioca izjavljenana zaključak Komunalne policije, broj 03-032-7-UP-31/3 od 24.10.2016. godine,",
    outcome: "partially",
    source_url: "https://sudovi.me/vrhs/odluka/257683",
